mapper.select:
        /* RegstCrCstmrMapper.chkCrCstmrRrn */
		SELECT  COUNT(*) AS CHK_CSTMR_RRN
		FROM    MSP_COURT_RCV
		WHERE   CSTMR_RRN = #{searchRrn}

mapper.insert:
        /* RegstCrCstmrMapper.regstCrCstmr */
		INSERT INTO MSP_COURT_RCV
		(
		    CR_SEQ
		    , CSTMR_NAME
		    , CSTMR_RRN
		    , CR_TP
		    , END_YN
		    , CR_COMP
		    , NO_JUDG
		    , JUDG_PAN
		    , RB_STRT_DT
		    , RB_ESTI
		    , RB_RATE
		    , RB_PRID
		    , AC_REG_DT
		    , REGST_ID
		    , REGST_DTTM
		    , RVISN_ID
		    , RVISN_DTTM
		) VALUES (
		    SEQ_CR_MST.NEXTVAL
		    , #{cstmrName}
		    , #{cstmrRrn}
		    , #{crTpCd}
		    , #{endYn}
		    , #{crComp}
		    , #{noJudg}
		    , #{judgPan}
		    , #{rbStrtDt}
		    , #{rbEsti}
		    , #{rbRate}
		    , #{rbPrid}
		    , #{acRegDt}
		    , #{sessionUserId}
		    , SYSDATE
		    , #{sessionUserId}
		    , SYSDATE
		)

mapper.select:
        /* RegstCrCstmrMapper.getCrSeq */
		SELECT  CR_SEQ
		FROM    MSP_COURT_RCV
		WHERE   CSTMR_RRN = #{cstmrRrn}

        /* RegstCrCstmrMapper.getLcMstSeq */
		SELECT  LC_SEQ AS LC_MST_SEQ
		FROM    MSP_LC_MST
		WHERE   CSTMR_RRN = #{cstmrRrn}
		AND		LC_STAT_CD = '2'

        /* RegstCrCstmrMapper.getLcDtlSeq */
		SELECT  LC_DTL_SEQ
		FROM    MSP_LC_DTL
		WHERE   LC_SEQ = #{lcMstSeq}

        /* RegstCrCstmrMapper.chkBondNum */
		SELECT COUNT(*)
		  FROM MSP_COURT_RCV_BOND
		 WHERE CR_SEQ = #{crSeq}
		   AND BOND_NUM = #{bondNum}

        /* RegstCrCstmrMapper.chkBondNumModi */
		SELECT COUNT(*)
		  FROM MSP_COURT_RCV_BOND
		 WHERE CR_BOND_SEQ = #{crBondSeq}
		   AND BOND_NUM = #{bondNum}

mapper.delete:
/* RegstCrCstmrMapper."deleteCrBond" */
DELETE FROM MSP_COURT_RCV_BOND
WHERE CR_BOND_SEQ = #{crBondSeq}

        /* RegstCrCstmrMapper."deleteCrRciv" */
		DELETE FROM MSP_COURT_RCV_RCIV
		WHERE CR_RCIV_SEQ = #{crRcivSeq}

mapper.select:
/* RegstCrCstmrMapper.getFileNmDtl */
SELECT  (FILE_DIR || FILE_NAME) AS FILE_NM
FROM    MSP_COURT_RCV_RCIV
WHERE   CR_RCIV_SEQ = #{crRcivSeq}

{CALL P_VAC_ONCE_VAC_ID(
		#{opCode, jdbcType=VARCHAR}
		, #{gubun, jdbcType=VARCHAR}
		, #{orderKey, jdbcType=VARCHAR}
		, #{vacBankCd, jdbcType=VARCHAR}
		, #{vacId, jdbcType=VARCHAR}
		, #{payAmt, jdbcType=VARCHAR}
		, #{sessionUserId, jdbcType=VARCHAR}
		, #{retCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
		, #{retMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
		, #{oVacBankCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
		, #{oVacBankNm, mode=OUT, javaType=string, jdbcType=VARCHAR}
		, #{oVacId, mode=OUT, javaType=string, jdbcType=VARCHAR}
	)
}

        /* RegstCrCstmrMapper.chkDclrDate */
		SELECT  DCLR_DATE
		FROM    MSP_COURT_RCV_ACCT
		WHERE   CR_SEQ = #{crSeq}
		AND		VAC_STAT = 'Y'

mapper.update:
        /* RegstCrCstmrMapper.updateDclrDate */
		UPDATE  MSP_COURT_RCV_ACCT
		SET     DCLR_DATE = #{dclrDate}
		WHERE   CR_SEQ = #{crSeq}
		AND		VAC_STAT = 'Y'

mapper.delete:
        /* RegstCrCstmrMapper.deleteCrInout */
		DELETE 	FROM MSP_COURT_RCV_INOUT
		WHERE 	CR_INOUT_SEQ = #{crInoutSeq}
